int popcount(int x) {
    int count = 0;
    while (x) {
        count += x & 1;
        x >>= 1;
    }
    return count;
}

// Function to calculate the popcount-depth of a number
int popcount_depth(int x) {
    int depth = 0;
    while (x != 1) {
        x = popcount(x);
        depth++;
    }
    return depth;
}

