    if (k == 0) return 0; // No number has depth 0
    if (n < 1) return 0; // No numbers in range [1, n]

    int64_t count = 0;
    for (int64_t i = 1; i <= n; i++) {
        if (popcount_depth(i) == k) {
            count++;
        }
    }
    return count;
}
